:root { --base: #11131c; --surface: #181b27; --overlay: #232838; --panel: #0e1019; --text: #eef1fb; --subtle: #aab2cc; --muted: #6b7392; --gold: #f4cf95; --love: #c4a7e7; --pine: #7aa2f7; --foam: #7ee0c0; }* { box-sizing: border-box; }html, body { margin: 0px; height: 100%; }body { background: radial-gradient(120% 120% at 50% 0%, #1a1d2b 0%, var(--base) 60%); color: var(--text); font-family: Inter, "Avenir Next", "Segoe UI", system-ui, sans-serif; display: flex; align-items: center; justify-content: center; padding: 3.5vh 4vw; }.paper { width: 100%; max-width: 1180px; background: var(--surface); border: 1px solid var(--overlay); border-radius: 16px; box-shadow: rgba(0, 0, 0, 0.5) 0px 24px 80px; overflow: hidden; }.head { padding: 24px 34px 6px; }.eyebrow { text-transform: uppercase; letter-spacing: 0.16em; font-size: 13px; color: var(--love); margin: 0px 0px 8px; }.head h1 { margin: 0px; font-size: 28px; line-height: 1.15; color: var(--gold); }.head p { margin: 8px 0px 0px; color: var(--subtle); font-size: 15.5px; max-width: 70ch; }.app { margin: 16px 34px 10px; height: 318px; display: flex; gap: 10px; background: var(--panel); border: 1px solid var(--overlay); border-radius: 12px; overflow: hidden; }.chat { flex: 1 1 58%; display: flex; flex-direction: column; min-width: 0px; }.chat .bar { display: flex; gap: 8px; align-items: center; padding: 9px 14px; border-bottom: 1px solid var(--overlay); font-family: "SF Mono", ui-monospace, monospace; font-size: 12px; color: var(--muted); }.chat .bar .dot { width: 9px; height: 9px; border-radius: 50%; }.chat .bar .r { background: rgb(224, 83, 63); }.chat .bar .y { background: var(--gold); }.chat .bar .g { background: var(--foam); }.chat .body { padding: 12px 14px; display: flex; flex-direction: column; gap: 8px; overflow: hidden; }.msg { max-width: 78%; padding: 8px 12px; border-radius: 12px; font-size: 13px; line-height: 1.45; }.msg.you { align-self: flex-end; background: rgb(32, 40, 63); border: 1px solid rgb(44, 54, 88); }.msg.k { align-self: flex-start; background: rgb(27, 34, 51); color: var(--subtle); border: 1px solid var(--overlay); }.typing { align-self: flex-start; color: var(--muted); font-size: 12px; font-style: italic; }.trace { flex: 0 0 38%; position: relative; display: flex; flex-direction: column; border-left: 1px solid var(--overlay); background: rgb(12, 14, 22); }.trace .thead { padding: 9px 12px; border-bottom: 1px solid var(--overlay); font-size: 11.5px; letter-spacing: 0.08em; text-transform: uppercase; color: var(--muted); display: flex; justify-content: space-between; }.trace .diagram { flex: 1 1 52%; padding: 12px; display: flex; align-items: center; justify-content: center; }.node { font-family: "SF Mono", ui-monospace, monospace; font-size: 11px; color: var(--subtle); border: 1px solid var(--overlay); border-radius: 7px; padding: 6px 10px; background: rgb(20, 24, 38); }.node.on { color: var(--pine); border-color: rgb(45, 63, 99); box-shadow: rgb(27, 39, 64) 0px 0px 0px 2px; }.arrow { color: var(--muted); margin: 0px 6px; }.trace .timeline { flex: 1 1 48%; border-top: 1px solid var(--overlay); padding: 8px 12px 56px; display: flex; flex-direction: column; gap: 5px; overflow: hidden; }.row { display: flex; align-items: center; gap: 7px; font-size: 11.5px; color: var(--subtle); }.row .tick { width: 6px; height: 6px; border-radius: 50%; background: var(--foam); flex: 0 0 auto; }.row .t { color: var(--muted); margin-left: auto; font-family: "SF Mono", ui-monospace, monospace; font-size: 10.5px; }.pet { position: absolute; left: 0px; right: 0px; bottom: 0px; height: 50px; display: flex; align-items: center; gap: 8px; padding: 0px 12px; background: linear-gradient(rgba(12, 14, 22, 0) 0%, rgb(12, 14, 22) 38%); border-top: 1px dashed rgb(29, 35, 54); }.pet svg { display: block; }.pet .sprite { animation: 2.4s ease-in-out 0s infinite normal none running bob; transform-origin: 50% 100%; }.pet .eye { animation: 4s steps(1) 0s infinite normal none running blink; transform-origin: center center; }.pet .label { font-size: 11px; color: var(--muted); }.pet .label b { color: var(--gold); font-weight: 600; }@keyframes bob { 
  0%, 100% { transform: translateY(0px); }
  50% { transform: translateY(-4px); }
}@keyframes blink { 
  0%, 92%, 100% { transform: scaleY(1); }
  95% { transform: scaleY(0.1); }
}.note { padding: 4px 34px 22px; display: flex; gap: 22px; flex-wrap: wrap; }.note .item { display: flex; gap: 8px; align-items: flex-start; max-width: 340px; }.note .k { color: var(--foam); font-size: 14px; line-height: 1.3; }.note .v { color: var(--subtle); font-size: 13px; line-height: 1.45; }.note .v b { color: var(--text); font-weight: 600; }.foot { padding: 0px 34px 24px; display: flex; align-items: center; gap: 14px; color: var(--muted); font-size: 12.5px; }.foot .badge { color: var(--gold); border: 1px solid var(--overlay); border-radius: 8px; padding: 5px 10px; background: var(--panel); }.foot .spacer { margin-left: auto; }
